body.script:
let map, svc, markers=[];
const types={all:['restaurant','cafe','bakery'],ristoranti:['restaurant'],bar:['cafe','bar'],gelaterie:['ice_cream_store'],pasticcerie:['bakery']};
let active='all';
function initMap(){
  map=new google.maps.Map(document.getElementById('map'),{center:{lat:44.4949,lng:11.3426},zoom:15,disableDefaultUI:true,styles:[{elementType:'geometry',stylers:[{color:'#050505'}]},{elementType:'labels.text.fill',stylers:[{color:'#9a9a9a'}]}]});
  svc=new google.maps.places.PlacesService(map);
  navigator.geolocation?.getCurrentPosition(p=>{map.setCenter({lat:p.coords.latitude,lng:p.coords.longitude});search();},()=>search());
  map.addListener('idle',search);
  map.addListener('click',hideSheet);
}
function hideSheet(){document.getElementById('sheet').style.transform='translateY(120%)'}
function clear(){markers.forEach(m=>m.setMap(null));markers=[]}
function add(p){const m=new google.maps.Marker({map,position:p.geometry.location,title:p.name});m.addListener('click',()=>show(p));markers.push(m)}
function search(){clear();const c=map.getCenter();types[active].forEach(t=>svc.nearbySearch({location:c,radius:1500,type:t},(r,s)=>{if(s==='OK')r.slice(0,20).forEach(add)}))}
function show(p){
  document.getElementById('s-title').textContent=p.name;
  document.getElementById('s-addr').textContent=p.vicinity||'';
  document.getElementById('s-rate').textContent=p.rating?'★ '+p.rating:'';
  document.getElementById('s-price').textContent=p.price_level?'€'.repeat(p.price_level):'';
  document.getElementById('s-open').textContent=p.opening_hours?(p.opening_hours.open_now?'🟢 Aperto':'🔴 Chiuso'):'';
  document.getElementById('s-dir').href=`https://www.google.com/maps/dir/?api=1&destination_place_id=${p.place_id}`;
  document.getElementById('sheet').style.transform='translateY(0)';
}
document.querySelectorAll('[data-type]').forEach(b=>b.onclick=()=>{active=b.dataset.type;document.querySelectorAll('[data-type]').forEach(x=>x.className='px-4 py-2 rounded-full bg-neutral-800/80 text-white/70 text-sm');b.className='px-4 py-2 rounded-full bg-orange-500 text-black font-semibold text-sm';search()});
document.getElementById('search').oninput=e=>{const q=e.target.value;if(q.length>2)svc.textSearch({query:q,location:map.getCenter(),radius:3000},(r,s)=>{if(s==='OK'){clear();r.forEach(add)}})};
